// Extract text from Gemini API response and split by platform
let text = '';
try {
  text = $input.first().json.candidates[0].content.parts[0].text || '';
} catch(e) {
  text = $input.first().json.text || $input.first().json.output || '';
}

const platform = $('Webhook').first().json.body.platform || 'both';

if (platform === 'both') {
  const facebookMatch = text.match(/===\s*FACEBOOK\s*===\s*([\s\S]*?)(?:===\s*INSTAGRAM\s*===|$)/i);
  const instagramMatch = text.match(/===\s*INSTAGRAM\s*===\s*([\s\S]*?)$/i);

  return [{
    json: {
      content: {
        facebook: facebookMatch ? facebookMatch[1].trim() : text,
        instagram: instagramMatch ? instagramMatch[1].trim() : text,
        raw: text
      }
    }
  }];
}

return [{
  json: {
    content: {
      [platform]: text.trim(),
      raw: text.trim()
    }
  }
}];

// Fallback: Extract text from the fallback model response
let text = '';
try {
  const json = $input.first().json;
  if (json.candidates) {
    text = json.candidates[0].content.parts[0].text || '';
  }
} catch(e) {}

if (!text) {
  // All models failed — return mock content
  text = '=== FACEBOOK ===\n[MOCK CONTENT - API LIMIT REACHED]\nWe\'ve hit the Gemini API rate limit! This is mock data so you can continue testing the UI and flow. 🚀\n\nAlways test with mock data if needed! #fallback #system\n=== INSTAGRAM ===\n[MOCK CONTENT - API LIMIT REACHED]\nHitting API limits? No problem! 😅 This mock data ensures you can keep evaluating the app\'s workflow and design.\n\nCheck your Google AI Studio plan to increase limits! 📸👇\n#mockdata #testing #socialmedia';
}

const platform = $('Webhook').first().json.body.platform || 'both';

if (platform === 'both') {
  const facebookMatch = text.match(/===\s*FACEBOOK\s*===\s*([\s\S]*?)(?:===\s*INSTAGRAM\s*===|$)/i);
  const instagramMatch = text.match(/===\s*INSTAGRAM\s*===\s*([\s\S]*?)$/i);
  return [{
    json: {
      content: {
        facebook: facebookMatch ? facebookMatch[1].trim() : text,
        instagram: instagramMatch ? instagramMatch[1].trim() : text,
        raw: text
      }
    }
  }];
}

return [{
  json: {
    content: {
      [platform]: text.trim(),
      raw: text.trim()
    }
  }
}];
